package main

import (
	"fmt"
	"net/http"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	userRequestCounter = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_request_total",
			Help: "Total number of requests per user",
		},
		[]string{"user", "request"},
	)
)

func init() {
	prometheus.MustRegister(userRequestCounter)
}

func handler(w http.ResponseWriter, r *http.Request) {
	user := r.URL.Query().Get("user")
	requestType := r.URL.Query().Get("request")

	if user == "" || requestType == "" {
		http.Error(w, "Missing 'user' or 'request' query parameter", http.StatusBadRequest)
		return
	}

	userRequestCounter.WithLabelValues(user, requestType).Inc()
	fmt.Fprintf(w, "Metrics updated for user: %s, request: %s\n", user, requestType)
}

func main() {
	http.HandleFunc("/metrics", promhttp.Handler().ServeHTTP)
	http.HandleFunc("/", handler)

	fmt.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}